## Why This Is Asked
Tests ability to bridge C memory life cycles, error handling, and CGO threading basics with opaque handles.

## Key Concepts
- CGO memory ownership and C.GoString
- Freeing C-allocated buffers with C.free
- Opaque C handles in Go wrappers
- Concurrent calls safety without shared state

## Code Example
```c
// config.h
typedef struct Config Config;
 Config* config_new(const char* json);
 const char* config_to_json(const Config* cfg);
 void config_free(Config* cfg);
```
```c
// config.c (minimal)
#include <stdlib.h>
#include <string.h>
#include "config.h"

struct Config { char* data; };
Config* config_new(const char* json){ if(!json) return NULL; Config* c=malloc(sizeof(Config)); c->data=strdup(json); return c; }
const char* config_to_json(const Config* cfg){ return cfg? cfg->data: NULL; }
void config_free(Config* cfg){ free(cfg->data); free(cfg); }
```
```go
// binding.go
package main

// #include "config.h"
// #cgo CFLAGS: -I.
import "C"
import (
  "errors"
  "unsafe"
)

type ConfigHandle struct{ ptr *C.Config }

func CreateConfig(json string) (*ConfigHandle, error){ cstr := C.CString(json); defer C.free(unsafe.Pointer(cstr)); cfg := C.config_new(cstr); if cfg == nil { return nil, errors.New("config creation failed") }; return &ConfigHandle{ptr: cfg}, nil }

func ConfigToJSON(h *ConfigHandle) (string, error){ if h==nil || h.ptr==nil { return "", errors.New("nil handle") }
  cstr := C.config_to_json(h.ptr); if cstr == nil { return "", nil }
  s := C.GoString(cstr); C.free(unsafe.Pointer((*C.char)(unsafe.Pointer(cstr))))
  return s, nil
}

func (h *ConfigHandle) Close() { if h!=nil && h.ptr!=nil { C.config_free(h.ptr); h.ptr = nil }
}
```

